  // Add season column if not exists
  try { db.exec\('ALTER TABLE factions ADD COLUMN season TEXT'\); } catch {}

  const seasons = {
    'Gallowdark': [
      'Imperial Navy Breachers','Hierotek Circle','Fellgor Ravagers',
      'Farstalker Kinband','Exaction Squad','Hearthkyn Salvagers',
      'Kasrkin','Hand of the Archon'
    ],
    'Bheta-Decima': [
      'Chaos Cult','Scout Squad','Brood Brothers','Inquisitorial Agents',
      'Nemesis Claw','Hernkyn Yaegirs','Blades of Khaine','Mandrakes'
    ],
    'Volkus': [
      'Tempestus Aquilons','Angels of Death','Goremongers','Raveners',
      'Vespid Stingwings','Ratlings','Sanctifiers','Plague Marines',
      'Wrecka Krew','Battleclade'
    ],
    'Tomb World': [
      'Deathwatch','Wolf Scouts','Celestian Insidiants','Canoptek Circle',
      'XV26 Stealth Battlesuits','Murderwing'
    ],
  };

  const upd = db.prepare\('UPDATE factions SET season = ? WHERE name = ?'\);
  let total = 0;
  for \(const [season, names] of Object.entries\(seasons\)\) {
    for \(const name of names\) {
      const r = upd.run\(season, name\);
      total += r.changes;
    }
  }
  console.log\(total + ' factions tagged with season'\);

